 97→export const mobileApi = {
 98→  async getJournals(cursor: string | null, limit = 10, userId?: string): Promise<CursorPage<JournalItem>> {
 99→    const params = new URLSearchParams();
100→    params.set('limit', String(limit));
101→    if (cursor) {
102→      params.set('before', cursor);
103→    }
104→    if (userId) {
105→      params.set('userId', userId);
106→    }
107→
108→    return apiRequest<CursorPage<JournalItem>>(`/journals?${params.toString()}`, {
109→      method: 'GET',
110→    });
111→  },
112→
113→  async getJournalById(journalId: string, userId?: string): Promise<{ journal: JournalItem }> {
114→    const params = new URLSearchParams();
115→    if (userId) {
116→      params.set('userId', userId);
117→    }
118→
119→    const suffix = params.toString() ? `?${params.toString()}` : '';
120→    return apiRequest<{ journal: JournalItem }>(`/journal/${encodeURIComponent(journalId)}${suffix}`, {
121→      method: 'GET',
122→    });
123→  },
124→
125→  async searchUsers(query: string, limit = 20): Promise<{ data: UserPreview[]; hasMore: boolean }> {
126→    const params = new URLSearchParams();
127→    params.set('query', query.trim());
128→    params.set('limit', String(limit));
129→
130→    return apiRequest<{ data: UserPreview[]; hasMore: boolean }>(`/users/search?${params.toString()}`, {
131→      method: 'GET',
132→    });
133→  },
134→
135→  async searchJournals(query: string, limit = 20, userId?: string): Promise<{ data: JournalItem[]; hasMore: boolean }> {
136→    const params = new URLSearchParams();
137→    params.set('query', query.trim());
138→    params.set('limit', String(limit));
139→    if (userId) {
140→      params.set('userId', userId);
141→    }
142→
143→    return apiRequest<{ data: JournalItem[]; hasMore: boolean }>(`/journals/search?${params.toString()}`, {
144→      method: 'GET',
145→    });
146→  },
147→
148→  async getNotifications(token: string, cursor: string | null, limit = 20): Promise<CursorPage<NotificationItem>> {
149→    const params = new URLSearchParams();
150→    params.set('limit', String(limit));
151→    if (cursor) {
152→      params.set('before', cursor);
153→    }
154→
155→    return apiRequest<CursorPage<NotificationItem>>(`/getNotifications?${params.toString()}`, {
156→      method: 'GET',
157→      headers: {
158→        ...authHeaders(token),
159→      },
160→    });
161→  },
162→
163→  async getStreak(userId: string): Promise<StreakResponse> {
164→    return apiRequest<StreakResponse>(`/streak/${encodeURIComponent(userId)}`, {
165→      method: 'GET',
166→    });
167→  },
168→
169→  async getUserData(userId: string): Promise<UserDataResponse> {
170→    const params = new URLSearchParams();
171→    params.set('userId', userId);
172→
173→    return apiRequest<UserDataResponse>(`/getUserData?${params.toString()}`, {
174→      method: 'GET',
175→    });
176→  },
177→
178→  async getUserByUsername(username: string): Promise<UserDataResponse> {
179→    return apiRequest<UserDataResponse>(
180→      `/user/${encodeURIComponent(username)}`,
181→      {method: 'GET'},
182→    );
183→  },
184→
185→  async getRelatedPosts(journalId: string): Promise<{data: JournalItem[]}> {
186→    return apiRequest<{data: JournalItem[]}>(
187→      `/journal/${encodeURIComponent(journalId)}/related`,
188→      {method: 'GET'},
189→    );
190→  },
191→
192→  async getUserJournals(token: string, userId: string, cursor: string | null, limit = 10): Promise<CursorPage<JournalItem>> {
193→    const params = new URLSearchParams();
194→    params.set('limit', String(limit));
195→    params.set('userId', userId);
196→    if (cursor) params.set('before', cursor);
197→    return apiRequest<CursorPage<JournalItem>>(`/userJournals?${params.toString()}`, {
198→      method: 'GET',
199→      headers: {Authorization: `Bearer ${token}`},
200→    });
201→  },
202→
203→  async saveJournal(token: string, payload: { title: string; plainText: string; html?: string }): Promise<{ message?: string }> {
204→    const formData = new FormData();
205→
206→    const lexicalPayload = {
207→      root: {
208→        children: [
209→          {
210→            type: 'paragraph',
211→            children: [
212→              {
213→                type: 'text',
214→                text: payload.plainText,
215→                detail: 0,
216→                format: 0,
217→                mode: 'normal',
218→                style: '',
219→                version: 1,
220→              },
221→            ],
222→            direction: null,
223→            format: '',
224→            indent: 0,
225→            version: 1,
226→          },
227→        ],
228→        direction: null,
229→        format: '',
230→        indent: 0,
231→        type: 'root',
232→        version: 1,
233→      },
234→    };
235→
236→    formData.append('title', payload.title);
237→    formData.append('content', JSON.stringify(lexicalPayload));
238→    formData.append('post_type', 'text');
239→
240→    return apiRequest<{ message?: string }>('/save-journal', {
241→      method: 'POST',
242→      headers: {
243→        ...authHeaders(token),
244→      },
245→      body: formData,
246→      timeoutMs: 30000,
247→      retries: 0,
248→    });
249→  },
250→};
